import org.junit.jupiter.api.Test;

class LeanCertificateCorpusTest {
	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();
	private static final CheckOptions RUNTIME_BAG = options(
			SemanticsTarget.RDF4J_RUNTIME,
			ObservationMode.BAG,
			ContextMode.ALL_BINDINGS);

	@Test
	void writesTheoremBackedV2Corpus() throws IOException {
		List<CertificateCase> cases = certificateCases();
		List<String> certificates = new ArrayList<>(cases.size());
		for (CertificateCase certificateCase : cases) {
			EquivalenceResult result = new AlgebraEquivalenceChecker(certificateCase.options())
					.check(certificateCase.original(), certificateCase.candidate());
			assertEquals(EquivalenceStatus.EQUIVALENT, result.getStatus(),
					() -> certificateCase.name() + ": " + result.getReason());
			NormalizationProof proof = assertInstanceOf(NormalizationProof.class, result.getEvidence().orElseThrow());
			NormalizationCertificate certificate = proof.getCertificate().orElseThrow();
			assertEquals(NormalizationCertificate.CURRENT_FORMAT_VERSION, certificate.getFormatVersion());
			assertTrue(certificate.getOriginalSteps().stream().allMatch(step -> step.getNodePath().equals("$")),
					certificateCase.name());
			assertTrue(certificate.getCandidateSteps().stream().allMatch(step -> step.getNodePath().equals("$")),
					certificateCase.name());
			certificates.add(certificate.toJson());
		}

		Path output = Path.of("target", "formal-certificates.jsonl");
		Files.createDirectories(output.getParent());
		Files.writeString(output, String.join("\n", certificates) + "\n");
		assertEquals(20, certificates.size());
	}

	private static List<CertificateCase> certificateCases() {
		TupleExpr leaf = leaf();
		List<CertificateCase> result = new ArrayList<>();
		add(result, "join-unit-left", RUNTIME_BAG, new Join(new SingletonSet(), leaf.clone()), leaf.clone());
		add(result, "join-unit-right", RUNTIME_BAG, new Join(leaf.clone(), new SingletonSet()), leaf.clone());
		add(result, "union-empty-left", RUNTIME_BAG, new Union(new EmptySet(), leaf.clone()), leaf.clone());
		add(result, "union-empty-right", RUNTIME_BAG, new Union(leaf.clone(), new EmptySet()), leaf.clone());
		add(result, "leftjoin-empty-left", RUNTIME_BAG, new LeftJoin(new EmptySet(), leaf.clone()), new EmptySet());
		add(result, "leftjoin-empty-right", RUNTIME_BAG, new LeftJoin(leaf.clone(), new EmptySet()), leaf.clone());
		add(result, "leftjoin-unit-right", RUNTIME_BAG,
				new LeftJoin(leaf.clone(), new SingletonSet(), new ValueConstant(VF.createLiteral(false))),
				leaf.clone());
		add(result, "minus-empty-left", RUNTIME_BAG, new Difference(new EmptySet(), leaf.clone()), new EmptySet());
		add(result, "minus-empty-right", RUNTIME_BAG, new Difference(leaf.clone(), new EmptySet()), leaf.clone());
		add(result, "filter-true-bag", RUNTIME_BAG,
				new Filter(leaf.clone(), new ValueConstant(VF.createLiteral(true))), leaf.clone());
		add(result, "filter-true-sequence",
				options(SemanticsTarget.RDF4J_RUNTIME, ObservationMode.SEQUENCE, ContextMode.ALL_BINDINGS),
				new Filter(leaf.clone(), new ValueConstant(VF.createLiteral(true))), leaf.clone());
		add(result, "distinct-idempotent", RUNTIME_BAG,
				new Distinct(new Distinct(leaf.clone())), new Distinct(leaf.clone()));
		add(result, "union-idempotent-set",
				options(SemanticsTarget.RDF4J_RUNTIME, ObservationMode.SET, ContextMode.ALL_BINDINGS),
				new Union(leaf.clone(), leaf.clone()), leaf.clone());
		add(result, "union-idempotent-ask",
				options(SemanticsTarget.SPARQL_1_1, ObservationMode.ASK, ContextMode.ALL_BINDINGS),
				new Union(leaf.clone(), leaf.clone()), leaf.clone());
		add(result, "distinct-hidden-set",
				options(SemanticsTarget.SPARQL_1_2_DRAFT, ObservationMode.SET, ContextMode.ALL_BINDINGS),
				new Distinct(leaf.clone()), leaf.clone());
		add(result, "distinct-hidden-ask",
				options(SemanticsTarget.BOTH_1_1_AND_1_2, ObservationMode.ASK, ContextMode.ALL_BINDINGS),
				new Distinct(leaf.clone()), leaf.clone());
		add(result, "reduced-hidden-set",
				options(SemanticsTarget.SPARQL_1_1, ObservationMode.SET, ContextMode.ALL_BINDINGS),
				new Reduced(leaf.clone()), leaf.clone());
		add(result, "reduced-hidden-ask",
				options(SemanticsTarget.SPARQL_1_2_DRAFT, ObservationMode.ASK, ContextMode.ALL_BINDINGS),
				new Reduced(leaf.clone()), leaf.clone());
		add(result, "values-empty", RUNTIME_BAG, emptyValues(), new EmptySet());
		add(result, "values-unit-both-top-level",
				options(SemanticsTarget.BOTH_1_1_AND_1_2, ObservationMode.BAG, ContextMode.TOP_LEVEL_EMPTY),
				unitValues(), new SingletonSet());
		return result;
	}

	private static void add(
			List<CertificateCase> result,
			String name,
			CheckOptions options,
			TupleExpr original,
			TupleExpr candidate) {
		result.add(new CertificateCase(name, options, original, candidate));
	}

	private static CheckOptions options(
			SemanticsTarget target,
			ObservationMode observation,
			ContextMode context) {
		return CheckOptions.builder()
				.semanticsTarget(target)
				.observationMode(observation)
				.contextMode(context)
				.boundedCounterexampleSearch(false)
				.build();
	}

	private static StatementPattern leaf() {
		return new StatementPattern(
				Var.of("s"),
				Var.of("p", VF.createIRI("urn:test:predicate")),
				Var.of("o"));
	}

	private static BindingSetAssignment emptyValues() {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setDeclaredBindingNames(Set.of("x"));
		assignment.setBindingSets(List.of());
		return assignment;
	}

	private static BindingSetAssignment unitValues() {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setDeclaredBindingNames(Set.of("x"));
		assignment.setBindingSets(List.of(EmptyBindingSet.getInstance()));
		return assignment;
	}

	private record CertificateCase(
			String name,
			CheckOptions options,
			TupleExpr original,
			TupleExpr candidate) {
	}
}
